type GraphType = 'contextweaver' | 'standard-rag' | 'multi-agent' | 'evaluator-optimizer' | 'routing-agent';

const graphs: Record<GraphType, { nodes: NodeData[], edges: EdgeData[], isNodeActive: (nodeId: string, step: string) => boolean }> = {
