"use client";

import React, { useRef, useState, useEffect } from 'react';
import { motion } from 'framer-motion';

export interface NodeData {
  id: string;
  label: string;
  x: number;
  y: number;
}

export interface EdgeData {
  source: string;
  target: string;
}

const defaultSteps: NodeData[] = [
  { id: 'doc', label: '📄 Document', x: 0, y: 100 },
  { id: 'chunker', label: '✂️ Chunker', x: 200, y: 100 },
  { id: 'vectordb', label: '🗄️ ChromaDB', x: 400, y: 0 },
  { id: 'prompt', label: '📝 Prompt Builder', x: 400, y: 200 },
  { id: 'qwen', label: '🧠 Qwen3-4B', x: 600, y: 100 },
  { id: 'results', label: '📊 Results', x: 800, y: 100 },
];

const defaultEdges: EdgeData[] = [
  { source: 'doc', target: 'chunker' },
  { source: 'chunker', target: 'vectordb' },
  { source: 'chunker', target: 'prompt' },
  { source: 'vectordb', target: 'prompt' },
  { source: 'prompt', target: 'qwen' },
  { source: 'qwen', target: 'results' },
];

export interface PipelineGraphProps {
  currentStep: string;
  nodes?: NodeData[];
  edges?: EdgeData[];
  isNodeActive?: (nodeId: string, currentStep: string) => boolean;
}

export default function PipelineGraph({ 
  currentStep, 
  nodes = defaultSteps, 
  edges = defaultEdges,
  isNodeActive = (nodeId, step) => {
    if (step === 'init' && nodeId === 'doc') return true;
    if ((step === 'chunking' || step === 'chunk_complete') && nodeId === 'chunker') return true;
    if ((step === 'retrieving' || step === 'retrieve_complete') && nodeId === 'vectordb') return true;
    if ((step === 'annotating' || step === 'annotate_complete') && (nodeId === 'prompt' || nodeId === 'qwen')) return true;
    if (step === 'merging' && nodeId === 'results') return true;
    if (step === 'done') return true;
    return false;
  }
}: PipelineGraphProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Need to wait for mount to render lines correctly to avoid hydration mismatch
  const [mounted, setMounted] = useState(false);
  const [, setRenderTick] = useState(0);

  const positions = useRef<{ [key: string]: { x: number, y: number } }>(
    nodes.reduce((acc, node) => {
      acc[node.id] = { x: node.x, y: node.y };
      return acc;
    }, {} as Record<string, { x: number, y: number }>)
  );

  useEffect(() => {
    let changed = false;
    nodes.forEach(node => {
      if (!positions.current[node.id]) {
        positions.current[node.id] = { x: node.x, y: node.y };
        changed = true;
      }
    });
    if (changed) {
      setRenderTick(t => t + 1);
    }
  }, [nodes]);

  useEffect(() => setMounted(true), []);

  return (
    <div 
      ref={containerRef}
      className="w-full h-[400px] border border-slate-700/50 rounded-xl bg-slate-900/50 backdrop-blur-sm relative overflow-hidden"
    >
      {/* Background grid pattern */}
      <div 
        className="absolute inset-0 opacity-20 pointer-events-none"
        style={{
          backgroundImage: 'radial-gradient(#334155 1px, transparent 1px)',
          backgroundSize: '20px 20px'
        }}
      />

      {/* SVG for edges */}
      {mounted && (
        <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
          <defs>
            <filter id="particle-glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="2" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {edges.map((edge, i) => {
            const sourcePos = positions.current[edge.source];
            const targetPos = positions.current[edge.target];
            if (!sourcePos || !targetPos) return null;

            const nodeWidth = 140;
            const nodeHeight = 50;
            const x1 = sourcePos.x + nodeWidth / 2 + 50;
            const y1 = sourcePos.y + nodeHeight / 2 + 50;
            const x2 = targetPos.x + nodeWidth / 2 + 50;
            const y2 = targetPos.y + nodeHeight / 2 + 50;

            const cx = (x1 + x2) / 2;
            const d = `M ${x1} ${y1} C ${cx} ${y1}, ${cx} ${y2}, ${x2} ${y2}`;
            const edgeId = `edge-${edge.source}-${edge.target}`;
            const active = isNodeActive(edge.source, currentStep) || isNodeActive(edge.target, currentStep);

            return (
              <motion.path
                key={edgeId}
                id={edgeId}
                d={d}
                fill="none"
                stroke={active ? "#06b6d4" : "#334155"}
                strokeWidth={active ? 3 : 2}
                className="transition-colors duration-500"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1, delay: i * 0.1 }}
              />
            );
          })}

          {/* Flowing particles along active edges */}
          {edges.map((edge) => {
            const active = isNodeActive(edge.source, currentStep) || isNodeActive(edge.target, currentStep);
            if (!active) return null;
            const edgeId = `edge-${edge.source}-${edge.target}`;
            return [0, 0.6, 1.2].map((offset, pi) => (
              <circle
                key={`particle-${edgeId}-${pi}`}
                r="4"
                fill="#22d3ee"
                filter="url(#particle-glow)"
                opacity="0.9"
              >
                <animateMotion
                  dur="1.8s"
                  begin={`${offset}s`}
                  repeatCount="indefinite"
                >
                  <mpath href={`#${edgeId}`} />
                </animateMotion>
              </circle>
            ));
          })}
        </svg>
      )}

      {/* Nodes */}
      <div className="absolute inset-0 p-[50px] z-10 pointer-events-none">
        {nodes.map((node) => {
          const active = isNodeActive(node.id, currentStep);
          return (
            <motion.div
              key={node.id}
              drag
              dragConstraints={containerRef}
              dragElastic={0}
              dragMomentum={false}
              initial={{ x: node.x, y: node.y }}
              onUpdate={(latest) => {
                if (latest.x !== undefined && latest.y !== undefined) {
                  const lx = typeof latest.x === 'number' ? latest.x : parseFloat(latest.x as string);
                  const ly = typeof latest.y === 'number' ? latest.y : parseFloat(latest.y as string);
                  if (!isNaN(lx) && !isNaN(ly)) {
                    positions.current[node.id] = { x: lx, y: ly };
                    setRenderTick(t => t + 1);
                  }
                }
              }}
              className={`absolute cursor-grab active:cursor-grabbing flex flex-col items-center justify-center w-[140px] h-[50px] rounded-lg border-2 pointer-events-auto transition-colors duration-300 ${
                active 
                  ? 'bg-cyan-950/90 border-cyan-400 text-white shadow-[0_0_20px_rgba(6,182,212,0.5)]' 
                  : 'bg-slate-800/90 border-slate-600 text-slate-300'
              }`}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              <span className="font-medium text-sm whitespace-nowrap">{node.label}</span>
              {active && (
                <motion.div 
                  layoutId={`active-indicator-${node.id}`}
                  className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1/2 h-[2px] bg-cyan-400 rounded-full shadow-[0_0_8px_rgba(6,182,212,1)]" 
                />
              )}
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

import React from 'react';
import { render, screen, fireEvent } from '@testing-library/react';
import ChunkInspector from '../ChunkInspector';

describe('ChunkInspector', () => {
  const mockChunkData = {
    chunk_idx: 1,
    confidence: 0.9,
    raw_text: 'This is raw text.',
    examples: [
      { text: 'Content 1', annotation: 'Annot 1', similarity_score: 0.95 },
      { text: 'Content 2', annotation: 'Annot 2', similarity_score: 0.85 },
    ],
    prompt: 'Please extract...',
    annotation: '{"entities": []}'
  };

  const mockOnClose = jest.fn();

  afterEach(() => {
    jest.clearAllMocks();
    document.body.style.overflow = '';
  });

  it('does not render when chunkData is null', () => {
    const { container } = render(<ChunkInspector chunkData={null} onClose={mockOnClose} />);
    expect(screen.queryByText('Chunk Inspector')).not.toBeInTheDocument();
  });

  it('renders correctly when chunkData is provided and modifies body overflow', () => {
    render(<ChunkInspector chunkData={mockChunkData} onClose={mockOnClose} />);

    // Portal renders to body
    expect(screen.getByText('Chunk Inspector')).toBeInTheDocument();
    expect(document.body.style.overflow).toBe('hidden');

    expect(screen.getByText('This is raw text.')).toBeInTheDocument();
    expect(screen.getByText('Content 1')).toBeInTheDocument();
    expect(screen.getByText('Content 2')).toBeInTheDocument();
    expect(screen.getByText('Please extract...')).toBeInTheDocument();
    expect(screen.getByText('{"entities": []}')).toBeInTheDocument();

    // Confidence ring renders 90%
    expect(screen.getByText('90%')).toBeInTheDocument();

    // Similarity score
    expect(screen.getByText('95.0%')).toBeInTheDocument();
    expect(screen.getByText('85.0%')).toBeInTheDocument();
  });

  it('calls onClose when close button or overlay is clicked', () => {
    render(<ChunkInspector chunkData={mockChunkData} onClose={mockOnClose} />);

    const closeButton = screen.getByRole('button', { name: 'Close' });
    fireEvent.click(closeButton);
    expect(mockOnClose).toHaveBeenCalledTimes(1);

    const overlay = document.querySelector('.fixed.inset-0') as HTMLElement;
    if (overlay) fireEvent.click(overlay);
    expect(mockOnClose).toHaveBeenCalledTimes(2);
  });

  it('renders correct confidence color when confidence is medium (0.7)', () => {
    render(<ChunkInspector chunkData={{ ...mockChunkData, confidence: 0.7 }} onClose={mockOnClose} />);
    expect(screen.getByText('70%')).toBeInTheDocument();
  });

  it('renders correct confidence color when confidence is low (0.5)', () => {
    render(<ChunkInspector chunkData={{ ...mockChunkData, confidence: 0.5 }} onClose={mockOnClose} />);
    expect(screen.getByText('50%')).toBeInTheDocument();
  });

  it('does not render ConfidenceRing when confidence is missing', () => {
    const dataWithoutConfidence = { ...mockChunkData };
    delete (dataWithoutConfidence as any).confidence;

    render(<ChunkInspector chunkData={dataWithoutConfidence} onClose={mockOnClose} />);
    expect(screen.queryByText('90%')).not.toBeInTheDocument();
  });

  it('stops propagation when clicking the modal content', () => {
    render(<ChunkInspector chunkData={mockChunkData} onClose={mockOnClose} />);
    const modalContent = screen.getByText('Chunk Inspector').parentElement?.parentElement as HTMLElement;
    fireEvent.click(modalContent);
    expect(mockOnClose).not.toHaveBeenCalled();
  });

  it('handles missing examples array gracefully', () => {
    const dataWithoutExamples = { ...mockChunkData };
    delete (dataWithoutExamples as any).examples;

    render(<ChunkInspector chunkData={dataWithoutExamples} onClose={mockOnClose} />);
    expect(screen.getByText('Chunk Inspector')).toBeInTheDocument();
    expect(screen.queryByText('Example 1')).not.toBeInTheDocument();
  });

  it('handles missing similarity_score in examples', () => {
    const dataWithMissingScore = { 
      ...mockChunkData, 
      examples: [{ text: 'Example 3', annotation: 'Annot 3' }] 
    };
    render(<ChunkInspector chunkData={dataWithMissingScore} onClose={mockOnClose} />);
    expect(screen.getByText('0.0%')).toBeInTheDocument();
  });

  it('resets overflow on unmount', () => {
    const { unmount } = render(<ChunkInspector chunkData={mockChunkData} onClose={mockOnClose} />);
    expect(document.body.style.overflow).toBe('hidden');
    unmount();
    expect(document.body.style.overflow).toBe('');
  });
});

import React from 'react';
